package ru.memearena.user.api;
import io.swagger.v3.oas.annotations.Operation; import jakarta.validation.Valid; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; import ru.memearena.user.application.UserProfileService; import java.util.*;
@RestController @RequestMapping("/api/v1/users") public class UserProfileController { private final UserProfileService service; public UserProfileController(UserProfileService service){this.service=service;} @PostMapping("/guest") @Operation(summary="Create guest user") public ResponseEntity<UserProfileResponse> create(@Valid @RequestBody CreateGuestUserRequest r){return ResponseEntity.status(HttpStatus.CREATED).body(UserProfileResponse.from(service.createGuest(r.nickname()).user()));} @GetMapping("/{userId}") @Operation(summary="Get public user profile") public UserProfileResponse get(@PathVariable UUID userId){return UserProfileResponse.from(service.get(userId));} }
